import redis
import json
import os
from typing import Optional, Dict, Any
from datetime import timedelta

class RedisCache:
    def __init__(self, redis_url: str = None, redis_cluster_nodes: list = None):
        if redis_cluster_nodes:
            self.redis_client = redis.RedisCluster(
                startup_nodes=redis_cluster_nodes,
                decode_responses=True,
                socket_timeout=5,
                socket_connect_timeout=5,
                health_check_interval=30
            )
        else:
            self.redis_client = redis.Redis(
                host=redis_url or os.getenv('REDIS_HOST', 'localhost'),
                port=int(os.getenv('REDIS_PORT', 6379)),
                db=int(os.getenv('REDIS_DB', 0)),
                decode_responses=True,
                socket_timeout=5,
                socket_connect_timeout=5
            )
    
    def set_session_token(self, user_id: str, token: str, ttl_minutes: int = 30) -> bool:
        try:
            key = f"session:{user_id}"
            self.redis_client.setex(
                key, 
                timedelta(minutes=ttl_minutes), 
                token
            )
            return True
        except Exception:
            return False
    
    def get_session_token(self, user_id: str) -> Optional[str]:
        try:
            key = f"session:{user_id}"
            return self.redis_client.get(key)
        except Exception:
            return None
    
    def set_api_key(self, user_id: str, api_key: str, ttl_hours: int = 24) -> bool:
        try:
            key = f"api_key:{user_id}"
            self.redis_client.setex(
                key, 
                timedelta(hours=ttl_hours), 
                api_key
            )
            return True
        except Exception:
            return False
    
    def get_api_key(self, user_id: str) -> Optional[str]:
        try:
            key = f"api_key:{user_id}"
            return self.redis_client.get(key)
        except Exception:
            return None
    
    def delete_session(self, user_id: str) -> bool:
        try:
            key = f"session:{user_id}"
            return bool(self.redis_client.delete(key))
        except Exception:
            return False
    
    def delete_api_key(self, user_id: str) -> bool:
        try:
            key = f"api_key:{user_id}"
            return bool(self.redis_client.delete(key))
        except Exception:
            return False
    
    def set_sensitive_data(self, key: str, data: Dict[str, Any], ttl_seconds: int = 3600) -> bool:
        try:
            serialized_data = json.dumps(data)
            self.redis_client.setex(key, ttl_seconds, serialized_data)
            return True
        except Exception:
            return False
    
    def get_sensitive_data(self, key: str) -> Optional[Dict[str, Any]]:
        try:
            data = self.redis_client.get(key)
            return json.loads(data) if data else None
        except Exception:
            return None

